<section class="account-page shell section-space-small"><div class="account-head"><p class="eyebrow">ISTORIC</p><h1>Comenzile mele</h1></div><div class="account-layout"><?php require BASE_PATH.'/app/Views/account/nav.php'; ?><div class="account-content"><section class="account-panel"><?php if(!$orders): ?><div class="empty-state"><h2>Nicio comandă încă</h2><a class="button" href="<?= e(url('/shop')) ?>">Descoperă colecția</a></div><?php else: ?><div class="account-orders detailed"><?php foreach($orders as $order): ?><a href="<?= e(url('/cont/comenzi/'.$order['order_number'])) ?>"><strong><?= e($order['order_number']) ?></strong><span><?= date('d.m.Y',strtotime($order['created_at'])) ?></span><em><?= e($order['order_status']) ?></em><b><?= money($order['grand_total_minor']) ?></b></a><?php endforeach; ?></div><?php endif; ?></section></div></div></section>

